using System.ComponentModel.DataAnnotations;

namespace CourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = "";

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 uppercase alphanumeric characters.")]
    public string StudentId { get; set; } = "";

    [Required(ErrorMessage = "Please select a course.")]
    public int? CourseId { get; set; }
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics, statistics, and data analysis." },
        new() { Id = "ENG", Name = "English", Description = "Literature, writing, and linguistic studies." },
        new() { Id = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = "HIST", Name = "History", Description = "Exploration of past events, cultures, and civilizations." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, CourseCode = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Instructor = "Dr. Sarah Chen", InstructorBio = "PhD in Computer Science from MIT. 10 years of teaching experience specializing in introductory CS education.", DepartmentId = "CS", IsFeatured = true },
        new() { Id = 2, CourseCode = "CS201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", Instructor = "Dr. James Park", InstructorBio = "Former Google engineer with expertise in algorithm optimization. Published researcher in computational complexity.", DepartmentId = "CS", IsFeatured = true },
        new() { Id = 3, CourseCode = "CS301", Title = "Database Systems", Description = "Design and implementation of relational databases. Covers SQL, normalization, indexing, and transaction management.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", Instructor = "Dr. Maria Lopez", InstructorBio = "Database architect with 15 years of industry experience. Contributor to PostgreSQL.", DepartmentId = "CS" },
        new() { Id = 4, CourseCode = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Instructor = "Dr. Robert Taylor", InstructorBio = "Award-winning educator with 20 years of experience in mathematics instruction.", DepartmentId = "MATH", IsFeatured = true },
        new() { Id = 5, CourseCode = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications to data science.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", Instructor = "Dr. Emily Wright", InstructorBio = "Researcher in applied mathematics. Consultant for machine learning startups.", DepartmentId = "MATH" },
        new() { Id = 6, CourseCode = "MATH301", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Instructor = "Dr. Emily Wright", InstructorBio = "Researcher in applied mathematics. Consultant for machine learning startups.", DepartmentId = "MATH" },
        new() { Id = 7, CourseCode = "ENG101", Title = "College Composition", Description = "Develop critical reading and academic writing skills. Focus on argumentation, research, and revision.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", Instructor = "Prof. Angela Morrison", InstructorBio = "Published author and writing coach. MFA from University of Iowa Writers' Workshop.", DepartmentId = "ENG" },
        new() { Id = 8, CourseCode = "ENG205", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present. Emphasis on cultural context.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", Instructor = "Dr. Thomas Reed", InstructorBio = "Specialist in 20th-century American fiction. Author of three scholarly monographs.", DepartmentId = "ENG" },
        new() { Id = 9, CourseCode = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based approach with laboratory component.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:00 PM", Instructor = "Dr. Alan Foster", InstructorBio = "Experimental physicist researching quantum materials. NASA collaborator.", DepartmentId = "PHYS", IsFeatured = true },
        new() { Id = 10, CourseCode = "PHYS202", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "Tue/Thu 10:00–11:30 AM + Lab Fri 2:00–4:00 PM", Instructor = "Dr. Alan Foster", InstructorBio = "Experimental physicist researching quantum materials. NASA collaborator.", DepartmentId = "PHYS" },
        new() { Id = 11, CourseCode = "HIST101", Title = "World Civilizations", Description = "Survey of major civilizations from antiquity to 1500 CE. Covers political, social, and cultural developments.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", Instructor = "Dr. Patricia Nguyen", InstructorBio = "Historian specializing in cross-cultural exchange. Fulbright scholar.", DepartmentId = "HIST" },
        new() { Id = 12, CourseCode = "HIST250", Title = "Modern European History", Description = "Europe from the Enlightenment to the present. Revolutions, world wars, and European integration.", Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM", Instructor = "Dr. William Hayes", InstructorBio = "Expert in 19th-century European political history. Published in leading historical journals.", DepartmentId = "HIST" },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? departmentId = null, string? search = null)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentId))
            query = query.Where(c => c.DepartmentId.Equals(departmentId, StringComparison.OrdinalIgnoreCase));

        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(c =>
                c.Title.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Contains(search, StringComparison.OrdinalIgnoreCase));

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
}

