arguments.file_text:
@page "/"
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Explore our departments and find your next course.</p>

<section class="featured-section">
    <h2>Featured Courses</h2>
    <div class="course-grid">
        @foreach (var course in featuredCourses)
        {
            <div class="course-card">
                <span class="badge">@course.CourseCode</span>
                <h3><a href="/courses/@course.Id">@course.Title</a></h3>
                <p>@course.Credits credits &middot; @course.Instructor</p>
                <p class="description">@course.Description</p>
            </div>
        }
    </div>
</section>

<section class="departments-section">
    <h2>Departments</h2>
    <div class="dept-grid">
        @foreach (var dept in departments)
        {
            <div class="dept-card">
                <h3><a href="/courses?department=@dept.Id">@dept.Name</a></h3>
                <p>@dept.Description</p>
            </div>
        }
    </div>
</section>

@code {
    private List<Course> featuredCourses = [];
    private List<Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetDepartments();
    }
}

.lead {
    font-size: 1.2rem;
    color: #555;
    margin-bottom: 2rem;
}

.featured-section, .departments-section {
    margin-bottom: 3rem;
}

.course-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 1.5rem;
}

.course-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.25rem;
    transition: box-shadow 0.2s;
}

.course-card:hover {
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
}

.course-card .badge {
    background-color: #1a237e;
    color: white;
    padding: 0.25rem 0.5rem;
    border-radius: 4px;
    font-size: 0.8rem;
    font-weight: bold;
}

.course-card h3 {
    margin: 0.75rem 0 0.5rem;
}

.course-card h3 a {
    color: #1a237e;
    text-decoration: none;
}

.course-card h3 a:hover {
    text-decoration: underline;
}

.course-card .description {
    color: #666;
    font-size: 0.9rem;
}

.dept-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1rem;
}

.dept-card {
