arguments.file_text:
@page "/courses"
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" action="/courses" class="filter-bar">
    <input type="text" name="search" value="@Search" placeholder="Search by title, code, or instructor..." class="search-input" />
    <select name="department" class="dept-select">
        <option value="">All Departments</option>
        @foreach (var dept in departments)
        {
            <option value="@dept.Id" selected="@(Department == dept.Id)">@dept.Name</option>
        }
    </select>
    <button type="submit" class="btn-search">Search</button>
</form>

@if (courses.Count == 0)
{
    <p class="no-results">No courses found matching your criteria.</p>
}
else
{
    <p class="result-count">Showing @courses.Count course(s)</p>
    <div class="course-list">
        @foreach (var course in courses)
        {
            <div class="course-row">
                <div class="course-info">
                    <span class="code">@course.CourseCode</span>
                    <a href="/courses/@course.Id" class="title">@course.Title</a>
                    <span class="meta">@course.Credits cr &middot; @course.Instructor &middot; @course.Schedule</span>
                </div>
                <a href="/courses/@course.Id" class="btn-detail">Details</a>
            </div>
        }
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public string? Department { get; set; }

    private List<Course> courses = [];
    private List<Department> departments = [];

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Department, Search);
    }
}

.filter-bar {
    display: flex;
    gap: 0.75rem;
    margin-bottom: 1.5rem;
    flex-wrap: wrap;
}

.search-input {
    flex: 1;
    min-width: 200px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
}

.dept-select {
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
}

.btn-search {
    padding: 0.5rem 1.25rem;
    background-color: #1a237e;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 1rem;
}

.btn-search:hover {
    background-color: #283593;
}

.result-count {
    color: #666;
    margin-bottom: 1rem;
}

.no-results {
    color: #888;
    font-style: italic;
}

.course-list {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.course-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 1rem 1.25rem;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
}

.course-row:hover {
