toolArgs.file_text:
@page "/courses/{Id:int}"
@inject CatalogService Catalog

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist. <a href="/courses">Browse all courses</a>.</p>
}
else
{
    <PageTitle>@course.Title - Course Catalog</PageTitle>

    <nav class="breadcrumb">
        <a href="/courses">Courses</a> &rsaquo;
        <a href="/courses?department=@course.DepartmentId">@course.DepartmentId</a> &rsaquo;
        <span>@course.CourseCode</span>
    </nav>

    <div class="course-detail">
        <header>
            <span class="code">@course.CourseCode</span>
            <h1>@course.Title</h1>
        </header>

        <div class="detail-grid">
            <section class="info-section">
                <h2>Description</h2>
                <p>@course.Description</p>

                <h2>Schedule</h2>
                <p>@course.Schedule</p>

                <div class="credits-badge">
                    <strong>@course.Credits</strong> Credits
                </div>
            </section>

            <aside class="instructor-section">
                <h2>Instructor</h2>
                <h3>@course.Instructor</h3>
                <p>@course.InstructorBio</p>
            </aside>
        </div>

        <div class="actions">
            <a href="/enroll?courseId=@course.Id" class="btn-enroll">Request Enrollment</a>
            <a href="/courses" class="btn-back">Back to Courses</a>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}

.breadcrumb {
    margin-bottom: 1.5rem;
    font-size: 0.9rem;
    color: #666;
}

.breadcrumb a {
    color: #1a237e;
    text-decoration: none;
}

.breadcrumb a:hover {
    text-decoration: underline;
}

.course-detail header .code {
    font-size: 0.9rem;
    font-weight: bold;
    color: #1a237e;
    text-transform: uppercase;
}

.course-detail header h1 {
    margin: 0.25rem 0 1.5rem;
}

.detail-grid {
    display: grid;
    grid-template-columns: 2fr 1fr;
    gap: 2rem;
    margin-bottom: 2rem;
}

@media (max-width: 768px) {
    .detail-grid {
        grid-template-columns: 1fr;
    }
}

.info-section h2,
.instructor-section h2 {
    font-size: 1.1rem;
    color: #333;
    border-bottom: 1px solid #e0e0e0;
    padding-bottom: 0.5rem;
    margin-bottom: 0.75rem;
}

.credits-badge {
    display: inline-block;
    background-color: #e8eaf6;
    padding: 0.5rem 1rem;
    border-radius: 4px;
    margin-top: 1rem;
}

.credits-badge strong {
    font-size: 1.25rem;
    color: #1a237e;
}

.instructor-section {
    background-color: #fafafa;
    padding: 1.25rem;
    border-radius: 8px;
    border: 1px solid #e0e0e0;
}

.instructor-section h3 {
    margin: 0 0 0.5rem;
    color: #1a237e;
}

.actions {
    display: flex;
    gap: 1rem;
}

.btn-enroll {
    padding: 0.6rem 1.5rem;
    background-color: #1a237e;
    color: white;
    text-decoration: none;
    border-radius: 4px;
    font-weight: 500;
}

.btn-enroll:hover {
    background-color: #283593;
}

.btn-back {
    padding: 0.6rem 1.5rem;
    background-color: #e0e0e0;
    color: #333;
    text-decoration: none;
    border-radius: 4px;
}

.btn-back:hover {
    background-color: #bdbdbd;
}

