arguments.file_text:
@page "/enroll"
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Request Enrollment</h1>
<p>Submit your enrollment request below. You will receive confirmation via your university email.</p>

@if (submitted)
{
    <div class="success-message">
        <h2>✓ Request Submitted</h2>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been received.</p>
        <p>Your student ID: @Model.StudentId</p>
        <a href="/courses">Browse more courses</a>
    </div>
}
else
{
    <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
        <DataAnnotationsValidator />
        <AntiforgeryToken />

        <div class="form-group">
            <label for="studentName">Full Name</label>
            <InputText id="studentName" @bind-Value="Model.StudentName" class="form-control" />
            <ValidationMessage For="() => Model.StudentName" />
        </div>

        <div class="form-group">
            <label for="studentId">Student ID</label>
            <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" placeholder="e.g. ABC12345" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="form-group">
            <label for="courseId">Course</label>
            <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-control">
                <option value="">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.CourseCode - @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn-submit">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm] private EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = [];
    private bool submitted;
    private string selectedCourseTitle = "";

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();

        if (CourseId.HasValue && Model.CourseId is null)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = Catalog.GetCourse(Model.CourseId ?? 0);
        selectedCourseTitle = course?.Title ?? "Unknown";
        submitted = true;
    }
}

.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.4rem;
    font-weight: 600;
    color: #333;
}

.form-control {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
}

.form-control:focus {
    outline: none;
    border-color: #1a237e;
    box-shadow: 0 0 0 2px rgba(26, 35, 126, 0.15);
}

.btn-submit {
    padding: 0.6rem 1.5rem;
    background-color: #1a237e;
    color: white;
    border: none;
    border-radius: 4px;
    font-size: 1rem;
    cursor: pointer;
    margin-top: 0.5rem;
}

.btn-submit:hover {
    background-color: #283593;
}

.success-message {
    background-color: #e8f5e9;
    border: 1px solid #a5d6a7;
    border-radius: 8px;
    padding: 1.5rem;
    max-width: 500px;
}

.success-message h2 {
    color: #2e7d32;
    margin-top: 0;
}

.success-message a {
    color: #1a237e;
}

:deep(.validation-message) {
    color: #c62828;
    font-size: 0.85rem;
    margin-top: 0.25rem;
}

